frame_eqs:
warp = 0;
wave_r = .5 + (wave_color1*sin(time*.555));
wave_g = .5 + (wave_color2*sin(time*.444));
wave_b = .5 + (wave_color3*sin(time*.666));
wave_mystery = wave_mysety + bass*.07;
decay = if(above((time*20)%20,0),decay,.7);
dx = .5;
dy = .5;
zoom = .7;
ob_r = if(above(treb,1.2),treb*.1,0);
q4=1;
q6=1;

wave_0_per_point:
ax=q4*(-1+2*sample);
ay=q2;
coef=sqrt(sin(3.1415*sample));
az=q3+q4*(rand(10000)*.0001)*coef;

ay=ay+.03*q4*sin(q4*.5*ax+q4*.75*(az-q3)+2*time+sin(q4*1.25*ax+q4*.75*(az-q3)+3*time));
dist=sqrt( sqr(ax)+sqr(az-q3) );
ay=ay+.05*sin(q4*2.5*dist-3.1415*time);

tcx=q4*(-1+.3333*(q7+.5));
tcz=q3+q4*(-1+.3333*(q8+.5));
dist=sqrt( sqr(ax-tcx)+sqr(az-tcz) );
sw=below(dist,.5*q4)*pow( (1-dist/(.5*q4)),8);
ay=ay-q4*sw*pow(q1,3);
a=a+sqrt(q1*sw);

ox = ax*t2 - (az-q3)*t1;
oy=ay;
oz = q3 + ax*t1 + (az-q3)*t2;

az=q3+(oz-q3)*t4-(oy-q2)*t3;
ay=q2+(oz-q3)*t3+(oy-q2)*t4;
ax=ox;

invz=1/(az+100);
x=.5+5*ax*invz;
y=.5+5*ay*invz;

