wave_2_per_frame:
t1=32;  // double num of rays

t5=6.2831*(.08*time-int(.08*time)); //speed
t8=0;


t3=-1+q7*.3333+.1667;
t4=-1+q8*.3333+.1667;

t6=pow( q1,3); // interpolation parameter

t2=sin(q5);
t7=cos(q5);

wave_2_per_point:
sample=.5*sample;

ns=equal(t8%t1,0);

ccx = .85*sin(5.234+100*sample+t5)*cos(200*6.2831*sample+ 3.14*sample+2.45+t5);
ccy = 1.5*sin(100*sample+0.456+t5)*sin(100*6.2831*sample+ 3.14*sample+1.12+t5);
ccz = .85*sin(3.12+100*sample+t5)*cos(300*6.2831*sample +3.14*sample+.95+t5);

rr=.075+.067*abs(sin(6.2831*ccy));
ccx=ccx*(1-t6)+ (t3+rr*cos(sample*6.2831+4*time))*t6;
ccz=ccz*(1-t6)+ (t4+rr*sin(sample*6.2831+4*time))*t6;

cenx=(1-ns)*cenx+ns*(q4*ccx);
ceny=(1-ns)*ceny+ns*(q2+q4*abs(ccy));
cenz=(1-ns)*cenz+ns*(q3+q4*ccz);
central=equal(t8%2,0);
angle=6.2831*(t8-1)/t1;

ax=cenx+(1-central)*q4*.02*q4*cos(angle+.12*ceny);
ay=ceny+(1-central)*q4*.02*q4*sin(angle+.12*ceny);
az=cenz;
a=central*above(t8,0)*.07;

ox = cenx+(ax-cenx)*t7+(az-cenz)*t2;
oy=ay;
oz = cenz+(ax-cenx)*-t2+(az-cenz)*t7;

ax=ox*t7-(oz-q3)*t2;
ay=oy;
az=q3+ox*t2+(oz-q3)*t7;

oz=q3+(az-q3)*cos(q6)-(ay-q2)*sin(q6);
oy=q2+(az-q3)*sin(q6)+(ay-q2)*cos(q6);
ox=ax;

invz=1/(oz+100);
x=.5+5*ox*invz;
y=.5+5*oy*invz;

t8=(t8+1)%t1;

